import{_ as e,o as d,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Page/page-settings.md","filePath":"vi-VN/Page/page-settings.md","lastUpdated":1781962217000}'),r={name:"vi-VN/Page/page-settings.md"};function o(i,t,g,l,c,h){return d(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings kiểm soát site display, upload page defaults, background images và admin panel appearance.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Site title</td><td>Title hiển thị trong browser tab.</td></tr><tr><td>Site icon</td><td>Icon nhỏ hiển thị trong browser tab.</td></tr><tr><td>ImgBed name</td><td>Name hiển thị trên frontend pages.</td></tr><tr><td>ImgBed logo</td><td>Logo image hiển thị trên frontend pages.</td></tr><tr><td>Logo link</td><td>URL mở khi click logo hoặc avatar.</td></tr><tr><td>Background switch interval</td><td>Rotation interval cho nhiều backgrounds, tính bằng milliseconds. <code>60000</code> nghĩa là 60 seconds.</td></tr><tr><td>Background opacity</td><td>Opacity của background image từ <code>0</code> đến <code>1</code>. Giá trị thấp hơn sẽ nhạt hơn.</td></tr><tr><td>Default URL prefix</td><td>Prefix dùng khi generate image links. Để trống sẽ dùng current site domain.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Announcement</td><td>Announcement hiển thị ở đầu upload page. Hỗ trợ HTML.</td></tr><tr><td>Default upload channel</td><td>Upload channel được chọn mặc định trên upload page. Cũng có thể chọn Smart Dispatch.</td></tr><tr><td>Default upload directory</td><td>Default upload directory, ví dụ <code>/user/</code>. Để trống hoặc <code>/</code> nghĩa là root.</td></tr><tr><td>Default naming method</td><td>Strategy generate filename mặc định sau upload. Xem bên dưới.</td></tr><tr><td>Convert to WebP by default</td><td>Convert images sang WebP trước khi upload.</td></tr><tr><td>Enable compression by default</td><td>Compress images local trong browser trước khi upload.</td></tr><tr><td>Default compression threshold</td><td>Tự động compress khi image vượt size này, tính bằng MB.</td></tr><tr><td>Default target size</td><td>Target file size sau compression, tính bằng MB.</td></tr><tr><td>Login page background</td><td>Background image cho user login page.</td></tr><tr><td>Upload page background</td><td>Background image cho upload page.</td></tr><tr><td>Footer portal link</td><td>URL mở khi nhấn footer portal button.</td></tr><tr><td>Hide footer</td><td>Khi enabled, ẩn frontend footer.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Admin login background</td><td>Background image cho admin login page.</td></tr><tr><td>Admin background</td><td>Background image cho admin pages. Dùng một image URL hoặc nhiều URLs.</td></tr><tr><td>Image loading mode</td><td>Preview loading mode cho admin file list. Original load original images. Smart loading ưu tiên thumbnails cho public images và originals cho restricted images.</td></tr><tr><td>Thumbnail source</td><td>Service dùng để generate thumbnails: wsrv.nl, Cloudflare Image Resizing hoặc WordPress Photon. Cloudflare Image Resizing phải được enable trong Cloudflare trước khi chọn.</td></tr><tr><td>Live2D widget</td><td>Hiển thị Live2D character trong admin panel.</td></tr><tr><td>Firework click effect</td><td>Hiển thị firework effect khi click page.</td></tr><tr><td>Star cursor trail</td><td>Hiển thị star trail khi di chuyển mouse.</td></tr></tbody></table><h2 id="background-image-formats" tabindex="-1">Background Image Formats <a class="header-anchor" href="#background-image-formats" aria-label="Permalink to &quot;Background Image Formats&quot;">​</a></h2><p>Login page background, upload page background và admin login background hỗ trợ các formats này:</p><table tabindex="0"><thead><tr><th>Value</th><th>Effect</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Dùng Bing wallpaper rotation.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Rotate nhiều images.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Dùng một background image.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Dùng random image API link. Bạn có thể cấu hình Random Image API của mình trong Other Settings, rồi paste generated random image link ở đây như single-background entry.</td></tr></tbody></table><p>Admin background hỗ trợ image URLs. Có thể tách nhiều URLs bằng English commas theo prompt trên page. Để trống sẽ dùng default background.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename, ví dụ <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>Chỉ time-random prefix và extension, ví dụ <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>Giữ original filename, ví dụ <code>cat.png</code>. Nếu trùng, ImgBed thêm <code>(1)</code>, <code>(2)</code>, v.v.</td></tr><tr><td>Short link</td><td>Dùng 8-character short ID và extension, ví dụ <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=e(r,[["render",o]]);export{m as __pageData,u as default};
